form:Form.form:Scripts:
		function Finished()
{
	EnableBack();	
	var param = "<DATA oi_liquidacion=\"" + Ctrl("id").GetXValue() + "\" oi_personal_emp=\"" +Ctrl("oi_personal_emp").GetXValue()+ "\"/>";	
	openNewFlowWait('NucleusRH.Base.Tiempos_Trabajados.Liquidacion_Personas.CONC_VAL.flow','REPORT',param,new ObjectResult(), "L");	
}

function EnableBack()
{       
	CtrlEnabled('BACK', true);
}

function LoadForm()
{
	switch(Ctrl("batch").Status)                               
	{
		case "finished":
			CtrlEnabled('BACK', true);
		break;

		default:
			CtrlEnabled('BACK', false);
		break;
	}
}

function ObjectResult()
{
	this.processResult = function()
	{		
	}
}
